    public DateTime? EstimatedDeliveryUtc { get; set; }
    public string? CustomerEmail { get; set; }
    public string? Notes { get; set; }
}

public class CreateShipmentDto
{
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public string? CustomerEmail { get; set; }
    public DateTime? EstimatedDeliveryUtc { get; set; }
    public string? Notes { get; set; }
}

public class UpdateShipmentStatusDto
{
    public ShipmentStatus Status { get; set; }
    public string? Notes { get; set; }
}

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Cancelled
}

using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentService(HttpClient http)
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        return await http.GetFromJsonAsync<List<ShipmentDto>>("api/shipments") ?? [];
    }

    public async Task<ShipmentDto?> GetShipmentByIdAsync(int id)
    {
        return await http.GetFromJsonAsync<ShipmentDto>($"api/shipments/{id}");
    }

    public async Task<ShipmentDto?> TrackShipmentAsync(string trackingNumber)
    {
        var response = await http.GetAsync($"api/shipments/track/{trackingNumber}");
        if (!response.IsSuccessStatusCode) return null;
        return await response.Content.ReadFromJsonAsync<ShipmentDto>();
    }

    public async Task<ShipmentDto?> CreateShipmentAsync(CreateShipmentDto dto)
    {
        var response = await http.PostAsJsonAsync("api/shipments", dto);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<ShipmentDto>();
    }

    public async Task UpdateStatusAsync(int id, UpdateShipmentStatusDto dto)
    {
        var response = await http.PutAsJsonAsync($"api/shipments/{id}/status", dto);
        response.EnsureSuccessStatusCode();
    }

    public async Task DeleteShipmentAsync(int id)
    {
        var response = await http.DeleteAsync($"api/shipments/{id}");
        response.EnsureSuccessStatusCode();
    }
}

using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments");

        group.MapGet("/", async (ApplicationDbContext db) =>
        {
            var shipments = await db.Shipments
                .OrderByDescending(s => s.CreatedAtUtc)
                .Select(s => ToDto(s))
                .ToListAsync();
            return Results.Ok(shipments);
        }).RequireAuthorization("Dispatcher");

        group.MapGet("/{id:int}", async (int id, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            return shipment is null ? Results.NotFound() : Results.Ok(ToDto(shipment));
        }).RequireAuthorization();

        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments
                .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            return shipment is null ? Results.NotFound() : Results.Ok(ToDto(shipment));
        }).RequireAuthorization();

        group.MapPost("/", async (CreateShipmentDto dto, ApplicationDbContext db) =>
        {
            var shipment = new Shipment
            {
                TrackingNumber = GenerateTrackingNumber(),
                Origin = dto.Origin,
                Destination = dto.Destination,
                Status = ShipmentStatus.Pending,
                CreatedAtUtc = DateTime.UtcNow,
                EstimatedDeliveryUtc = dto.EstimatedDeliveryUtc,
                CustomerEmail = dto.CustomerEmail,
                Notes = dto.Notes
            };

            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();
            return Results.Created($"api/shipments/{shipment.Id}", ToDto(shipment));
        }).RequireAuthorization("Dispatcher");

        group.MapPut("/{id:int}/status", async (int id, UpdateShipmentStatusDto dto, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();

            shipment.Status = dto.Status;
            if (dto.Notes is not null) shipment.Notes = dto.Notes;
            await db.SaveChangesAsync();
            return Results.Ok(ToDto(shipment));
        }).RequireAuthorization("Dispatcher");

        group.MapDelete("/{id:int}", async (int id, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();

            db.Shipments.Remove(shipment);
            await db.SaveChangesAsync();
            return Results.NoContent();
        }).RequireAuthorization("Dispatcher");
    }

    private static ShipmentDto ToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = s.Status,
        CreatedAtUtc = s.CreatedAtUtc,
        EstimatedDeliveryUtc = s.EstimatedDeliveryUtc,
        CustomerEmail = s.CustomerEmail,
        Notes = s.Notes
    };

    private static string GenerateTrackingNumber()
    {
        return $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Guid.NewGuid().ToString()[..8].ToUpperInvariant()}";
    }
}

