<PageTitle>Track Shipment</PageTitle>

<h2 class="mb-4">🔍 Track Your Shipment</h2>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input class="form-control" placeholder="Enter tracking number (e.g. SHP-20260528-A1B2C3D4)"
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="TrackShipment" disabled="@isLoading">
                @if (isLoading)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Track
            </button>
        </div>
    </div>
</div>

@if (notFound)
{
    <div class="alert alert-warning">
        <strong>Not found.</strong> No shipment matches tracking number <code>@searchedNumber</code>. Please check and try again.
    </div>
}

@if (shipment is not null)
{
    <div class="card">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">Shipment <code>@shipment.TrackingNumber</code></h5>
            <span class="badge @GetStatusBadge(shipment.Status) fs-6">@shipment.Status</span>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Origin</dt>
                        <dd>@shipment.Origin</dd>
                        <dt>Destination</dt>
                        <dd>@shipment.Destination</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Created</dt>
                        <dd>@shipment.CreatedAtUtc.ToString("yyyy-MM-dd HH:mm") UTC</dd>
                        <dt>Estimated Delivery</dt>
                        <dd>
                            @if (shipment.EstimatedDeliveryUtc.HasValue)
                            {
                                @shipment.EstimatedDeliveryUtc.Value.ToString("yyyy-MM-dd")
                                <span class="text-muted">(@GetDeliveryCountdown(shipment.EstimatedDeliveryUtc.Value))</span>
                            }
                            else
                            {
                                <span class="text-muted">Not yet estimated</span>
                            }
                        </dd>
                    </dl>
                </div>
            </div>

            @if (shipment.Notes is not null)
            {
                <div class="mt-2">
                    <strong>Notes:</strong> @shipment.Notes
                </div>
            }

            <hr />
            <h6>Delivery Progress</h6>
            <div class="progress" style="height: 30px;">
                <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                     role="progressbar"
                     style="width: @GetProgressPercent(shipment.Status)%"
                     aria-valuenow="@GetProgressPercent(shipment.Status)"
                     aria-valuemin="0" aria-valuemax="100">
                    @shipment.Status
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = "";
    private string searchedNumber = "";
    private ShipmentDto? shipment;
    private bool notFound;
    private bool isLoading;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter") await TrackShipment();
    }

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isLoading = true;
        notFound = false;
        shipment = null;
        searchedNumber = trackingNumber.Trim();

        shipment = await ShipmentService.TrackShipmentAsync(searchedNumber);
        notFound = shipment is null;
        isLoading = false;
    }

    private static string GetDeliveryCountdown(DateTime estimatedUtc)
    {
        var diff = estimatedUtc.Date - DateTime.UtcNow.Date;
        if (diff.TotalDays < 0) return "Past due";
        if (diff.TotalDays == 0) return "Today";
        return $"in {(int)diff.TotalDays} day(s)";
    }

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Cancelled => 100,
        _ => 0
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-primary progress-bar-striped progress-bar-animated"
    };

    private static string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}
