@page "/dispatcher"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize(Policy = "Dispatcher")]
@rendermode InteractiveAuto
@inject ShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h2 class="mb-4">📦 Dispatcher Dashboard</h2>

<div class="d-flex justify-content-between align-items-center mb-3">
    <div>
        <input class="form-control" placeholder="Filter by destination..." @bind="filterText" @bind:event="oninput" style="width: 300px;" />
    </div>
    <button class="btn btn-primary" @onclick="ShowCreateForm">+ New Shipment</button>
</div>

@if (showCreateForm)
{
    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title">Create Shipment</h5>
            <EditForm Model="newShipment" OnValidSubmit="CreateShipment" FormName="createShipment">
                <DataAnnotationsValidator />
                <div class="row g-3">
                    <div class="col-md-4">
                        <label class="form-label">Origin</label>
                        <InputText class="form-control" @bind-Value="newShipment.Origin" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Destination</label>
                        <InputText class="form-control" @bind-Value="newShipment.Destination" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Customer Email</label>
                        <InputText class="form-control" @bind-Value="newShipment.CustomerEmail" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Estimated Delivery (UTC)</label>
                        <InputDate class="form-control" @bind-Value="newShipment.EstimatedDeliveryUtc" />
                    </div>
                    <div class="col-md-8">
                        <label class="form-label">Notes</label>
                        <InputText class="form-control" @bind-Value="newShipment.Notes" />
                    </div>
                </div>
                <div class="mt-3">
                    <button type="submit" class="btn btn-success" disabled="@isSubmitting">Create</button>
                    <button type="button" class="btn btn-secondary ms-2" @onclick="() => showCreateForm = false">Cancel</button>
                </div>
            </EditForm>
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!FilteredShipments.Any())
{
    <p>No shipments found.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Customer</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var s in FilteredShipments)
                {
                    <tr>
                        <td><code>@s.TrackingNumber</code></td>
                        <td>@s.Origin</td>
                        <td>@s.Destination</td>
                        <td><span class="badge @GetStatusBadge(s.Status)">@s.Status</span></td>
                        <td>@(s.CustomerEmail ?? "—")</td>
                        <td>@(s.EstimatedDeliveryUtc?.ToString("yyyy-MM-dd") ?? "—")</td>
                        <td>
                            @if (editingId == s.Id)
                            {
                                <select class="form-select form-select-sm d-inline-block w-auto" @bind="editStatus">
                                    @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                    {
                                        <option value="@status">@status</option>
                                    }
                                </select>
                                <button class="btn btn-sm btn-success ms-1" @onclick="() => SaveStatus(s.Id)">Save</button>
                                <button class="btn btn-sm btn-secondary ms-1" @onclick="() => editingId = null">Cancel</button>
                            }
                            else
                            {
                                <button class="btn btn-sm btn-outline-primary" @onclick="() => StartEdit(s)">Update</button>
                                <button class="btn btn-sm btn-outline-danger ms-1" @onclick="() => DeleteShipment(s.Id)">Delete</button>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = "";
    private bool showCreateForm;
    private bool isSubmitting;
    private CreateShipmentDto newShipment = new();
    private int? editingId;
    private ShipmentStatus editStatus;

    private IEnumerable<ShipmentDto> FilteredShipments =>
        shipments?.Where(s =>
            string.IsNullOrEmpty(filterText) ||
            s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase)) ?? [];

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private void ShowCreateForm()
    {
        newShipment = new();
        showCreateForm = true;
    }

    private async Task CreateShipment()
    {
        isSubmitting = true;
        await ShipmentService.CreateShipmentAsync(newShipment);
        shipments = await ShipmentService.GetAllShipmentsAsync();
        showCreateForm = false;
        isSubmitting = false;
    }

    private void StartEdit(ShipmentDto s)
    {
        editingId = s.Id;
        editStatus = s.Status;
    }

    private async Task SaveStatus(int id)
    {
        await ShipmentService.UpdateStatusAsync(id, new UpdateShipmentStatusDto { Status = editStatus });
        shipments = await ShipmentService.GetAllShipmentsAsync();
        editingId = null;
    }

    private async Task DeleteShipment(int id)
    {
        await ShipmentService.DeleteShipmentAsync(id);
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private static string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

